import{_ as a,c as l,o,a5 as t,j as e}from"./chunks/framework.Dtwt352Q.js";const u=JSON.parse('{"title":"v1.1.35：大量性能改进，新增服务器管理","description":"","frontmatter":{},"headers":[],"relativePath":"changelog/v1.1.35.md","filePath":"changelog/v1.1.35.md","lastUpdated":1772014034000}'),n={name:"changelog/v1.1.35.md"};function r(s,i,d,p,c,m){return o(),l("div",null,[...i[0]||(i[0]=[t('<h1 id="v1-1-35-大量性能改进-新增服务器管理" tabindex="-1">v1.1.35：大量性能改进，新增服务器管理 <a class="header-anchor" href="#v1-1-35-大量性能改进-新增服务器管理" aria-label="Permalink to “v1.1.35：大量性能改进，新增服务器管理”">​</a></h1><p><strong>发布日期</strong>：2026年01月25日</p><hr><h2 id="一句话总结" tabindex="-1">一句话总结 <a class="header-anchor" href="#一句话总结" aria-label="Permalink to “一句话总结”">​</a></h2><p>这次更新大幅提升了工作区创建性能，增加了服务器管理功能，并修复了多个用户体验问题。</p><hr><h2 id="新功能-服务器管理" tabindex="-1">新功能：服务器管理 <a class="header-anchor" href="#新功能-服务器管理" aria-label="Permalink to “新功能：服务器管理”">​</a></h2><h3 id="这次更新了什么" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>新增了服务器管理界面，可以更方便地管理 OpenCode 服务器连接。</p><h3 id="如何使用" tabindex="-1">如何使用？ <a class="header-anchor" href="#如何使用" aria-label="Permalink to “如何使用？”">​</a></h3><p>在 Desktop 应用中：</p><ol><li>打开设置，找到&quot;服务器&quot;选项</li><li>点击&quot;管理服务器&quot;进入管理界面</li><li>添加、删除或编辑你的服务器配置</li></ol><hr><h2 id="新功能-模型配置改进" tabindex="-1">新功能：模型配置改进 <a class="header-anchor" href="#新功能-模型配置改进" aria-label="Permalink to “新功能：模型配置改进”">​</a></h2><h3 id="这次更新了什么-1" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么-1" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>改进了模型配置功能，现在可以更灵活地设置 Kimi K2.5 模型的参数，并为 GitHub Copilot GPT-5 模型添加了 xhigh 推理级别。</p><h3 id="如何使用-1" tabindex="-1">如何使用？ <a class="header-anchor" href="#如何使用-1" aria-label="Permalink to “如何使用？”">​</a></h3><ol><li>打开模型设置</li><li>选择 Kimi K2.5 模型</li><li>调整推荐的 topP 和 temperature 设置</li></ol><hr><h2 id="新功能-工作区性能提升" tabindex="-1">新功能：工作区性能提升 <a class="header-anchor" href="#新功能-工作区性能提升" aria-label="Permalink to “新功能：工作区性能提升”">​</a></h2><h3 id="这次更新了什么-2" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么-2" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>大幅加快了工作区创建速度，让新建项目更流畅。</p><h3 id="对你的影响" tabindex="-1">对你的影响 <a class="header-anchor" href="#对你的影响" aria-label="Permalink to “对你的影响”">​</a></h3><p>新建工作区时不再需要长时间等待，体验更加流畅。</p><hr><h2 id="新功能-支持多种新模型" tabindex="-1">新功能：支持多种新模型 <a class="header-anchor" href="#新功能-支持多种新模型" aria-label="Permalink to “新功能：支持多种新模型”">​</a></h2><h3 id="这次更新了什么-3" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么-3" aria-label="Permalink to “这次更新了什么？”">​</a></h3><ul><li>支持 GPT-5.1-Codex 模型（在 Codex 认证插件中）</li><li>支持多种推理提供商</li></ul><hr><h2 id="要不要升级" tabindex="-1">要不要升级？ <a class="header-anchor" href="#要不要升级" aria-label="Permalink to “要不要升级？”">​</a></h2><table tabindex="0"><thead><tr><th>情况</th><th>建议</th></tr></thead><tbody><tr><td>使用 Desktop 版</td><td>✅ 推荐升级（性能提升明显）</td></tr><tr><td>使用多个服务器</td><td>✅ 推荐升级</td></tr><tr><td>用得好好的</td><td>可以等下次</td></tr></tbody></table><p><strong>升级命令</strong>：</p>',32),e("div",{class:"language-bash"},[e("button",{title:"Copy Code",class:"copy"}),e("span",{class:"lang"},"bash"),e("pre",null,[e("code",{"v-pre":""},"opencode upgrade")])],-1),t('<hr><h2 id="技术细节-可跳过" tabindex="-1">技术细节（可跳过） <a class="header-anchor" href="#技术细节-可跳过" aria-label="Permalink to “技术细节（可跳过）”">​</a></h2><details><summary>点击展开完整更新列表</summary><h3 id="core" tabindex="-1">Core <a class="header-anchor" href="#core" aria-label="Permalink to “Core”">​</a></h3><ul><li>Add tests</li><li>Sync changes from upstream</li><li>Fix models snapshot loading to prevent caching issues</li><li>Fix Nix configuration</li><li>Fix unicode filename handling in snapshot diff by disabling quote escaping</li><li>Deep merge providerOptions in applyCaching to preserve nested configuration (@zerone0x)</li><li>Construct apply_patch metadata before requesting permission in web interface (@brittlewis12)</li><li>Remove models.dev macro</li><li>Tell the model what model it is in the environment section of the prompt</li><li>Retry web fetch with simple user agent on 403 errors (@Arasple)</li><li>Allow GPT-5.1-Codex model in Codex auth plugin (@Danztee)</li><li>Bump gitlab-ai-provider version (@vglafirov)</li><li>Add model information as part of task metadata (@shantur)</li><li>Add xhigh reasoning effort for GitHub Copilot GPT-5 models (@Arthur742Ramos)</li><li>Normalize path separators for session diff filtering on Windows (@alexyaroshuk)</li><li>Faster workspace creation</li></ul><h3 id="tui" tabindex="-1">TUI <a class="header-anchor" href="#tui" aria-label="Permalink to “TUI”">​</a></h3><ul><li>Fix question selection click when terminal is unfocused (@maharshi365)</li><li>Use min/maxHeight for question textarea</li><li>Permission prompt should ignore keyboard events while dialog stack length is greater than zero (@justfortheloveof)</li><li>Use selectedForeground for question prompt tab text visibility (@ariane-emory)</li><li>Always center selected item in selection dialogs (@ariane-emory)</li></ul><h3 id="desktop" tabindex="-1">Desktop <a class="header-anchor" href="#desktop" aria-label="Permalink to “Desktop”">​</a></h3><ul><li>Fix submit button state in app</li><li>Fix unnecessary suspense flash in app</li><li>Add active state to comment cards in prompt input</li><li>Fix type error</li><li>Terminal clone needs remount to function properly</li><li>Remove terminal connection error overlay</li><li>Remove space between ellipsis and truncated text in comment card tooltip</li><li>Update status popover empty state text color and centering</li><li>Prevent focus on share popover text field</li><li>Add link icon and use it for copy-to-clipboard buttons in UI</li><li>Adjust share popover position 64px to the left</li><li>Update share popover gutter to 6px and radius to match status dropdown</li><li>Add 8px spacing between share button and icon buttons in titlebar</li><li>Replace Popover with DropdownMenu for server options in app</li><li>Update options icon button styling with improved active state and hover effects</li><li>Change server item actions div padding from px-4 to pl-4</li><li>Add onFilter callback to List component and hide add server row during search</li><li>Position status circle inside input wrapper and fix dialog padding</li><li>Remove hover background color from server list items</li><li>Allow add server row to grow for error messages in app</li><li>Update add server button and row styling in app</li><li>Update manage servers dialog styling and behavior</li><li>Add truncation tooltip to server items in status popover</li><li>Update server and MCP item styles in status popover</li><li>Update status popover styling and positioning</li><li>Use 4px border radius (rounded-sm) consistently in app components</li><li>Update titlebar spacing and status popover styling in app</li><li>Enable submit button when comment cards are present in app</li><li>Add back button in subagent sessions (@tomzhu1024)</li><li>Model select dropdown not closing when pressing Escape key</li><li>Improve model selector user experience</li><li>Fix inability to select text when creating a new session</li><li>Fix scrolling in unpaid model selector</li><li>Fix Adam integration issue</li><li>Add critical shadow for comment input validation and set editor popover radius to 14px</li><li>Improve comment popover with better error styling and click-outside detection</li><li>Change prompt placeholder based on comment count in app</li><li>Adjust prompt container padding to 16px on bottom and horizontal sides</li><li>Adjust prompt input positioning to 12px from bottom and right edges, remove session panel bottom padding</li><li>Add escape/click-away to close read-only comment popovers, 10px radius, and remove &#39;Click to view context&#39; text</li><li>Don&#39;t use findLast in app package</li><li>Add state to pause existing audio for demo menus and add support for audio controls (@jcampuza)</li><li>Implement new server management for web and desktop (@OpeOginni)</li><li>New workspace appears expanded and at the top of the list</li><li>Missing translations in app</li><li>Better error screen when connecting to sidecar</li><li>Fix line selection issues in the app</li><li>Fixed reactive loops in the app</li><li>Better session stream rendering performance</li><li>Add Iosevka as a font choice in desktop app (@ariane-emory)</li><li>Always close hovercard when view-sessions is clicked (@DNGriffin)</li><li>Close comment input popover on Escape key or click away</li><li>Use shadow-lg-border-base on read-only comment popovers and align label spacing</li><li>Remove border from comment input popover</li><li>Position read-only comment popover below icon with 4px gutter</li><li>Style comment popovers with 14px radius, move label below comment, and adjust text colors and sizes</li><li>Move filename and line count below comment text in popovers</li><li>Add tooltip with path, 6px spacing before close icon, and reduce filename truncation to 14 characters in editor tabs</li><li>Add middle truncation for filename in comment card</li><li>Truncate filename from start to show end of path in the app</li><li>Remove gap between filename and comment in comment card</li><li>Add shadow-xs-border with hover state to comment card</li><li>Fix comment card styling with 48px height, 2px gap, and truncated filename while preserving line count visibility</li><li>Increase comment font size to 12px in the app</li><li>Add 8px gap before close icon and truncate long filenames in app</li><li>Keep close icon in top right of comment card</li><li>Add transition-all to comment card hover states</li><li>Add close-small icon and use it for comment card dismiss button</li><li>Truncate comment text and set card max-width to 200px in app</li><li>Indent comment text to align with filename in context card</li><li>Style submitted comment icons to match comment popup style</li><li>Update prompt input styling with refined borders, hover states, and spacing</li><li>Update context cards styling with 8px padding/gap and 6px border radius</li><li>Add button-primary-base variable and use primary variant for Comment button</li><li>Improve comment popup styling and add new comment icon</li><li>Center checkbox indicator in provider selection (@ProdigyRahul)</li><li>Auto-open OAuth links for Codex and Copilot (@edoedac0)</li><li>Close delete workspace dialog immediately</li><li>Don&#39;t remount directory layout in app for better performance</li><li>Reapply work in progress changes for line selection feature in app</li><li>Revert line selection work in progress</li><li>Fix view all sessions flakiness in app (@DNGriffin)</li></ul><p><strong>Thank you to 18 community contributors:</strong></p><p>@ProdigyRahul:</p><ul><li>fix(app): enable dialog dismiss on model selector (dialog.tsx) (#10203)</li><li>fix(app): center checkbox indicator in provider selection (#10267)</li><li>fix(app): tooltip text in light mode to use inverted neutral scale (#9786)</li><li>fix(app): markdown rendering with morphdom for better dom functions (#10373)</li></ul><p>@DNGriffin:</p><ul><li>fix(app): View all sessions flakiness (#10149)</li><li>fix(app): Fix plan mode btn keyboard a11y issues (#10330)</li><li>fix(app): Always close hovercard when view-sessions clicked (#10326)</li></ul><p>@shantur:</p><ul><li>docs(ecosystem): Add CodeNomad entry to ecosystem documentation (#10222)</li><li>feat(tasks): Add model info as part of metadata (#10307)</li></ul><p>@edoedac0:</p><ul><li>feat(app): auto-open oauth links for codex and copilot (#10258)</li></ul><p>@ariane-emory:</p><ul><li>feat: always center selected item in selection dialogs (resolves #10209) (#10207)</li><li>feat(desktop): add Iosevka as a font choice (resolves #10103) (#10347)</li><li>fix(tui): Use selectedForeground for question prompt tab text visibility (resolves #10334) (#10337)</li></ul><p>@alexyaroshuk:</p><ul><li>fix(app): normalize path separators for session diff filtering on Windows (#10291)</li></ul><p>@Arthur742Ramos:</p><ul><li>fix: add xhigh reasoning effort for GitHub Copilot GPT-5 models (#10092)</li></ul><p>@vglafirov:</p><ul><li>fix: bump gitlab-ai-provider version (#10255)</li></ul><p>@Danztee:</p><ul><li>fix: allow gpt-5.1-codex model in codex auth pluginFixes (#10181)</li></ul><p>@Arasple:</p><ul><li>fix: retry webfetch with simple UA on 403 (#10328)</li></ul><p>@neriousy:</p><ul><li>feat(docs): add a desktop troubleshooting guide (#10397)</li></ul><p>@justfortheloveof:</p><ul><li>fix: permission prompt should ignore keyboard events while dialog stack len &gt; 0 (#10338)</li></ul><p>@brittlewis12:</p><ul><li>fix(web): construct apply_patch metadata before requesting permission (#10422)</li></ul><p>@OpeOginni:</p><ul><li>feat(web): implement new server management for web and desktop (#8513)</li></ul><p>@zerone0x:</p><ul><li>fix(provider): deep merge providerOptions in applyCaching (#10323)</li></ul><p>@jcampuza:</p><ul><li>fix: add state to pause existing audio for demo menus, add support fo… (#10428)</li></ul><p>@maharshi365:</p><ul><li>fix(opentui): question selection click when terminal unfocused (#9731)</li></ul><p>@tomzhu1024:</p><ul><li>feat(app): back button in subagent sessions (#10439)</li></ul></details><hr><p><a href="./">← 返回更新日志</a></p>',5)])])}const f=a(n,[["render",r]]);export{u as __pageData,f as default};
